import React, { useState } from 'react'
import axios from 'axios';
import { Button, IconButton } from '@material-ui/core';
import PhotoCameraIcon from '@material-ui/icons/PhotoCamera';

export default function UploadFile() {
    const [data, setData] = useState({
        name: '',
        studentID: '',
        password: ''
    })

    const handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;

        setData(data => ({...data, [name]: value}));
    }

    const handleSubmit = (event) => {
        event.preventDefault();
        const sendData = {
            name:data.name,
            studentID:data.studentID,
            password:data.password
        }
        axios.post('http://localhost:80/api/register.php', sendData)
        .then((result) => {
            console.log(result.data)
            if(result.data.Status == 'Invalid') {
                alert('Invalid User');
            } else {
                console.log('Sent')
            }
        })
    };
  return (
    <center>
    <div> 
        


        Upload Here
        <form onSubmit={handleSubmit}>


            <input style={{display: 'none'}} accept="image/*" id="icon-button-file" type="file" />
      <label htmlFor="icon-button-file">
        <IconButton color="secondary" type='submit' name='submit' variant='contained' aria-label="upload picture" component="span">
          <PhotoCameraIcon />
        </IconButton>
      </label>


        </form>
    

        </div>
    </center>





    //     {/* <<?php if (isset($_GET['error'])): ?>
	// 	<p><?php echo $_GET['error']; ?></p>
	// <?php endif ?>
    //  <form action="testUpload.php"
    //        method="post"
    //        encType="multipart/form-data">

    //        <input type="file" 
    //               name="my_image" />

    //        <input type="submit" 
    //               name="submit"
    //               value="Upload" />
     	
    //  </form> */}
   
  )
}
